def validate_rdec(rdec, known_decisions):
    # C-TOTALITY: Ensure rdec is a dict and known_decisions is a list
    if not isinstance(rdec, dict):
        return {"ok": False, "problems": ["rdec must be a dict"]}
    if not isinstance(known_decisions, list):
        return {"ok": False, "problems": ["known_decisions must be a list"]}

    problems = []

    # C1: All listed fields must be present
    required_fields = ["rdec_id", "decision", "axis", "why_required", "expected_decision_effect", "omission_risk", "stop_condition_ref"]
    for field in required_fields:
        if field not in rdec:
            problems.append(f"Missing required field: {field}")

    # If missing required fields, return early
    if problems:
        return {"ok": False, "problems": problems}

    # C2: decision must be in known_decisions
    decision = rdec["decision"]
    if not isinstance(decision, str):
        problems.append("decision must be a string")
    elif decision not in known_decisions:
        problems.append(f"decision '{decision}' not found in known_decisions")

    # C3: expected_decision_effect must be non-empty string
    expected_decision_effect = rdec["expected_decision_effect"]
    if not isinstance(expected_decision_effect, str) or not expected_decision_effect.strip():
        problems.append("expected_decision_effect must be a non-empty string")

    # C4: omission_risk must be non-empty string
    omission_risk = rdec["omission_risk"]
    if not isinstance(omission_risk, str) or not omission_risk.strip():
        problems.append("omission_risk must be a non-empty string")

    # C5: stop_condition_ref must be non-empty string
    stop_condition_ref = rdec["stop_condition_ref"]
    if not isinstance(stop_condition_ref, str) or not stop_condition_ref.strip():
        problems.append("stop_condition_ref must be a non-empty string")

    # C6: Ensure other string fields are strings (defensive, though not explicitly required by spec)
    # rdec_id, axis, why_required, and decision already checked for presence; now validate types
    for field in ["rdec_id", "axis", "why_required"]:
        if not isinstance(rdec[field], str):
            problems.append(f"{field} must be a string")

    return {"ok": len(problems) == 0, "problems": problems}
